 128→const normalizeApiPath = (path = '') => (
 129→    String(path).startsWith('/api/')
 130→        ? String(path).slice(4)
 131→        : String(path)
 132→);
 133→
 134→const canonicalizeMetricsPath = (rawPath = '') => {
 135→    const normalized = normalizeApiPath(rawPath);
 136→    return normalized
 137→        .replace(/\/[0-9a-f]{8}-[0-9a-f-]{27,}(?=\/|$)/ig, '/:id')
 138→        .replace(/\/\d+(?=\/|$)/g, '/:id');
 139→};
