 141→const isPersonalizedGetRequest = (req) => {
 142→    if (req?.headers?.authorization) {
 143→        return true;
 144→    }
 145→
 146→    const userId = String(req?.query?.userId || '').trim();
 147→    const loggedInUserId = String(req?.query?.loggedInUserId || '').trim();
 148→    return Boolean(userId || loggedInUserId);
 149→};
