 201→const pickFirstNonEmptyString = (...values) => {
 202→    for (const value of values) {
 203→        if (typeof value === 'string') {
 204→            const trimmed = value.trim();
 205→            if (trimmed) return trimmed;
 206→        }
 207→    }
 208→    return '';
 209→};
