 383→const evaluateShareImageCandidate = (rawUrl) => {
 384→    const absoluteUrl = resolveAbsoluteHttpUrl(rawUrl);
 385→    if (!absoluteUrl) {
 386→        return {
 387→            ok: false,
 388→            reason: 'invalid_or_non_http_url',
 389→            resolvedUrl: null,
 390→        };
 391→    }
 392→
 393→    let path = '';
 394→    try {
 395→        const parsed = new URL(absoluteUrl);
 396→        path = String(parsed.pathname || '').toLowerCase();
 397→    } catch {
 398→        return {
 399→            ok: false,
 400→            reason: 'invalid_resolved_url',
 401→            resolvedUrl: null,
 402→        };
 403→    }
 404→
 405→    if (path.endsWith('.svg')) {
 406→        return {
 407→            ok: false,
 408→            reason: 'svg_not_supported_for_share_image',
 409→            resolvedUrl: absoluteUrl,
 410→        };
 411→    }
 412→
 413→    if (!isSafeRemoteImageUrl(absoluteUrl)) {
 414→        return {
 415→            ok: false,
 416→            reason: 'unsafe_remote_url',
 417→            resolvedUrl: absoluteUrl,
 418→        };
 419→    }
 420→
 421→    return {
 422→        ok: true,
 423→        reason: 'ok',
 424→        resolvedUrl: absoluteUrl,
 425→    };
 426→};
