 487→const convertToOgJpeg = async (inputBuffer) => {
 488→    return sharp(inputBuffer, { limitInputPixels: 60_000_000 })
 489→        .rotate()
 490→        .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, {
 491→            fit: 'contain',
 492→            background: { r: 255, g: 255, b: 255, alpha: 1 },
 493→        })
 494→        .jpeg({ quality: 82, mozjpeg: true })
 495→        .toBuffer();
 496→};
