 544→app.use((req, res, next) => {
 545→    metricsState.requests += 1;
 546→    metricsState.inFlight += 1;
 547→
 548→    const startNs = process.hrtime.bigint();
 549→    let byteCount = 0;
 550→
 551→    const originalWrite = res.write.bind(res);
 552→    const originalEnd = res.end.bind(res);
 553→
 554→    res.write = (chunk, encoding, callback) => {
 555→        if (chunk) {
 556→            byteCount += Buffer.isBuffer(chunk)
 557→                ? chunk.length
 558→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 559→        }
 560→        return originalWrite(chunk, encoding, callback);
 561→    };
 562→
 563→    res.end = (chunk, encoding, callback) => {
 564→        if (chunk) {
 565→            byteCount += Buffer.isBuffer(chunk)
 566→                ? chunk.length
 567→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 568→        }
 569→        return originalEnd(chunk, encoding, callback);
 570→    };
 571→
 572→    res.on('finish', () => {
 573→        metricsState.inFlight = Math.max(0, metricsState.inFlight - 1);
 574→        metricsState.responses += 1;
 575→        metricsState.bytesSent += byteCount;
 576→
 577→        const statusBucket = classifyStatusBucket(res.statusCode);
 578→        metricsState.statusBuckets[statusBucket] += 1;
 579→
 580→        const durationMs = Number(process.hrtime.bigint() - startNs) / 1_000_000;
 581→        const routeTemplate = req.route?.path
 582→            ? `${req.baseUrl || ''}${req.route.path}`
 583→            : req.path;
 584→        const routeKey = `${req.method} ${canonicalizeMetricsPath(routeTemplate)}`;
 585→
 586→        let routeStat = metricsState.routeStats.get(routeKey);
 587→        if (!routeStat) {
 588→            if (metricsState.routeStats.size >= METRICS_ROUTE_LIMIT) {
 589→                return;
 590→            }
 591→
 592→            routeStat = {
 593→                count: 0,
 594→                totalDurationMs: 0,
 595→                maxDurationMs: 0,
 596→                bytesSent: 0,
 597→                statusBuckets: { '2xx': 0, '3xx': 0, '4xx': 0, '5xx': 0, other: 0 },
 598→            };
 599→            metricsState.routeStats.set(routeKey, routeStat);
 600→        }
 601→
 602→        routeStat.count += 1;
 603→        routeStat.totalDurationMs += durationMs;
 604→        routeStat.maxDurationMs = Math.max(routeStat.maxDurationMs, durationMs);
 605→        routeStat.bytesSent += byteCount;
 606→        routeStat.statusBuckets[statusBucket] += 1;
 607→    });
 608→
 609→    next();
 610→});
