 633→// ── Profile share route: composite OG image for social media ──
 634→app.get('/share/u/:username/image', async (req, res) => {
 635→    const { username } = req.params;
 636→
 637→    // Serve from cache if available
 638→    const cached = getShareImageCached(`profile:${username}`);
 639→    if (cached) {
 640→        res.set('Content-Type', 'image/jpeg');
 641→        res.set('Cache-Control', 'public, max-age=3600');
 642→        return res.send(cached);
 643→    }
 644→
 645→    await ensureShareFonts();
 646→
 647→    try {
 648→        const result = await getUserByUsernameService(username);
 649→        const user = result?.userData?.[0];
 650→        if (!user) {
 651→            return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 652→        }
 653→
 654→        const displayName = normalizeWhitespace(user.name) || username;
 655→        const handle = `@${normalizeWhitespace(user.username || username)}`;
 656→        const bio = toPreviewText(user.bio || '', 120);
 657→
 658→        // ── Fetch background image ──
 659→        let bgBuffer = null;
 660→        const bgStyle = user.background || {};
 661→        const bgImageMatch = typeof bgStyle.backgroundImage === 'string'
 662→            ? bgStyle.backgroundImage.match(/url\(["']?([^"')]+)["']?\)/)
 663→            : null;
 664→        const bgImageUrl = bgImageMatch?.[1];
 665→
 666→        if (bgImageUrl) {
 667→            const bgEval = evaluateShareImageCandidate(bgImageUrl);
 668→            if (bgEval.ok && bgEval.resolvedUrl) {
 669→                try {
 670→                    const remote = await fetchRemoteImageBuffer(bgEval.resolvedUrl);
 671→                    bgBuffer = remote.buffer;
 672→                } catch { /* use fallback gradient */ }
 673→            }
 674→        }
 675→
 676→        // ── Base layer: background or dark gradient ──
 677→        let baseLayer;
 678→        if (bgBuffer) {
 679→            baseLayer = await sharp(bgBuffer, { limitInputPixels: 60_000_000 })
 680→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, { fit: 'cover' })
 681→                .toBuffer();
 682→        } else {
 683→            // Use profile's solid background color if available, otherwise dark fallback
 684→            const solidColor = (typeof bgStyle.background === 'string' && /^#[0-9a-fA-F]{3,8}$/.test(bgStyle.background.trim()))
 685→                ? bgStyle.background.trim()
 686→                : null;
 687→            const gradientSvg = solidColor
 688→                ? `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 689→                    <rect width="100%" height="100%" fill="${solidColor}"/>
 690→                </svg>`
 691→                : `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 692→                    <defs><linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="100%">
 693→                        <stop offset="0%" stop-color="#1a1a2e"/>
 694→                        <stop offset="100%" stop-color="#16213e"/>
 695→                    </linearGradient></defs>
 696→                    <rect width="100%" height="100%" fill="url(#g)"/>
 697→                </svg>`;
 698→            baseLayer = await sharp(Buffer.from(gradientSvg))
 699→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT)
 700→                .png()
 701→                .toBuffer();
 702→        }
 703→
 704→        // ── Dark overlay for text readability ──
 705→        const overlaySvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 706→            <rect width="100%" height="100%" fill="black" fill-opacity="0.55"/>
 707→        </svg>`;
 708→        const overlayBuffer = await sharp(Buffer.from(overlaySvg)).png().toBuffer();
 709→
 710→        // ── Circular avatar ──
 711→        let avatarComposite = null;
 712→        const avatarSize = 180;
 713→        const avatarUrl = user.image_url;
 714→        if (avatarUrl) {
 715→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
 716→            if (avatarEval.ok && avatarEval.resolvedUrl) {
 717→                try {
 718→                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
 719→                    const circleMask = Buffer.from(
 720→                        `<svg width="${avatarSize}" height="${avatarSize}">
 721→                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
 722→                        </svg>`
 723→                    );
 724→                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
 725→                        .resize(avatarSize, avatarSize, { fit: 'cover' })
 726→                        .png()
 727→                        .toBuffer();
 728→                    const circularAvatar = await sharp(resizedAvatar)
 729→                        .composite([{ input: circleMask, blend: 'dest-in' }])
 730→                        .png()
 731→                        .toBuffer();
 732→                    avatarComposite = circularAvatar;
 733→                } catch { /* skip avatar */ }
 734→            }
 735→        }
 736→
 737→        // ── Compose all layers ──
 738→        const composites = [
 739→            { input: overlayBuffer, top: 0, left: 0 },
 740→        ];
 741→
 742→        if (avatarComposite) {
 743→            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
 744→            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
 745→        }
 746→
 747→        const finalImage = await sharp(baseLayer)
 748→            .composite(composites)
 749→            .jpeg({ quality: 82, mozjpeg: true })
 750→            .toBuffer();
 751→
 752→        setShareImageCached(`profile:${username}`, finalImage);
 753→        res.set('Content-Type', 'image/jpeg');
 754→        res.set('Cache-Control', 'public, max-age=3600');
 755→        return res.send(finalImage);
 756→    } catch (err) {
 757→        console.error('profile share image route error:', err?.message || err);
 758→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 759→    }
 760→});
