1004→const isMetricsAuthorized = (req) => {
1005→    if (!METRICS_TOKEN) {
1006→        return true;
1007→    }
1008→
1009→    const providedToken = String(req.headers['x-metrics-token'] || '').trim();
1010→    return Boolean(providedToken && providedToken === METRICS_TOKEN);
1011→};
1012→
1013→const buildMetricsPayload = () => {
1014→    const routeStats = Array.from(metricsState.routeStats.entries())
1015→        .map(([route, stat]) => ({
1016→            route,
1017→            count: stat.count,
1018→            avgDurationMs: stat.count > 0 ? Number((stat.totalDurationMs / stat.count).toFixed(2)) : 0,
1019→            maxDurationMs: Number(stat.maxDurationMs.toFixed(2)),
1020→            bytesSent: stat.bytesSent,
1021→            statusBuckets: stat.statusBuckets,
1022→        }))
1023→        .sort((a, b) => b.count - a.count);
1024→
1025→    return {
1026→        startedAt: metricsState.startedAt,
1027→        requests: metricsState.requests,
1028→        responses: metricsState.responses,
1029→        inFlight: metricsState.inFlight,
1030→        bytesSent: metricsState.bytesSent,
1031→        statusBuckets: metricsState.statusBuckets,
1032→        routeStats: routeStats,
1033→    };
1034→};
